Question.Javascript:
		/ds/var/page/OracleReportForm/AllWarrants
		P_DEF1_FLAG
		Services.getValue(AllWarrants.dataBinding)
		Check box to print by Issue Date or uncheck to access Second Defendant Field.
		return true;
		1

        // 10 Aug 2006 - TD4177 Kevin Gichohi (EDS) - Changed setDefault to initialise so that the AllWarrants.dataBinding field can have a default value of 'Y'.
		Services.setValue(AllWarrants.dataBinding, "Y");

		AllWarrants.dataBinding
		
			var allWarrants = Services.getValue(AllWarrants.dataBinding);
			if (! CaseManUtils.isBlank(allWarrants))
			{
				if (allWarrants == "Y")
				{
					Status_RunReportButton.validationList = ["IssueDate", "PaymentDate"];
				}
				else
				{
					Status_RunReportButton.validationList = ["CaseNumber", "WarrantNumber", "PaymentDate"];
				}
			}
		
		
			var SEARCH_RESULTS_XPATH = PAGE_XPATH + "/tmp/Warrants";
			AllWarrants.modelValue = {checked: 'Y', unchecked: 'N'};
			
			Status_RunReportButton.enableOn = [AllWarrants.dataBinding, IssueDate.dataBinding, PaymentDate.dataBinding, CaseNumber.dataBinding, WarrantNumber.dataBinding, SEARCH_RESULTS_XPATH];
			Status_RunReportButton.isEnabled = function()
			{
				//alert("isEnabled");
				var allWarrants = Services.getValue(AllWarrants.dataBinding);
				//alert(allWarrants);
				if (! CaseManUtils.isBlank(allWarrants))
				{
					if (allWarrants == "N")
					{
						var caseNumber = Services.getValue(CaseNumber.dataBinding);
						//alert("Case : " + caseNumber);
						if ( caseNumber == null || CaseManUtils.isBlank(caseNumber))
						{
							//alert("due to case");
							return false;
						}
				        
				        var errCode = validateWarrant();
						if (errCode == null)
						{
							return true;
						}
						else
						{
							return false;
						}	        				
					}
					else
					{
						//alert("Becasue of Y");
						return true;
					}
				}
				else
				{
					//alert("Blanked");
					return false;
				}				
			}
